// 线性插值 (lerp)
function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

// 对于四元数旋转，使用 slerp (球面线性插值)
function slerp(a: Quat, b: Quat, t: number): Quat {
  let cosHalfTheta = Quat.dot(a, b);
  // 如果点积为负，翻转一个四元数以走最短路径
  if (cosHalfTheta < 0) {
    b = Quat.conjugate(b);
    cosHalfTheta = -cosHalfTheta;
  }
