}

// Cubic Hermite 插值公式
// 给定两个关键帧: (t0, p0, m0) 和 (t1, p1, m1)
// 在 t0 和 t1 之间的时间 t 处:
// s = (t - t0) / (t1 - t0)  // 归一化时间 [0, 1]
// h00 = 2s^3 - 3s^2 + 1     // Hermite 基函数
// h10 = s^3 - 2s^2 + s
// h01 = -2s^3 + 3s^2
// h11 = s^3 - s^2
// value = h00*p0 + h10*(t1-t0)*m0 + h01*p1 + h11*(t1-t0)*m1

